import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar/Navbar';
import Footer from './components/Footer/Footer';
import FloatingCTA from './components/FloatingCTA/FloatingCTA';
import Home from './pages/Home/Home';
import UpcomingShow from './pages/UpcomingShow/UpcomingShow';
import ModelScreening from './pages/ModelScreening/ModelScreening';
import DesignersMeet from './pages/DesignersMeet/DesignersMeet';
import Workshop from './pages/Workshop/Workshop';
import BecomeModel from './pages/BecomeModel/BecomeModel';
import HireModel from './pages/HireModel/HireModel';
import Portfolio from './pages/Portfolio/Portfolio';
import Contact from './pages/Contact/Contact';
import ApplySuccess from './pages/ApplySuccess/ApplySuccess';

function App() {
  return (
    <Router>
      <div className="app-wrapper">
        <Navbar />
        <main>
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/upcoming-show" element={<UpcomingShow />} />
            <Route path="/model-screening" element={<ModelScreening />} />
            <Route path="/designers-meet" element={<DesignersMeet />} />
            <Route path="/workshop" element={<Workshop />} />
            <Route path="/become-a-model" element={<BecomeModel />} />
            <Route path="/hire-a-model" element={<HireModel />} />
            <Route path="/portfolio" element={<Portfolio />} />
            <Route path="/contact" element={<Contact />} />
            <Route path="/apply-success" element={<ApplySuccess />} />
          </Routes>
        </main>
        <Footer />
        <FloatingCTA />
      </div>
    </Router>
  );
}

export default App;
